-- Get the stage IDs
SET @l1_stage_id = (SELECT id FROM approvalStages WHERE stageName = 'L1 - Initial Review' ORDER BY id DESC LIMIT 1);
SET @l2_stage_id = (SELECT id FROM approvalStages WHERE stageName = 'L2 - Security Approval' ORDER BY id DESC LIMIT 1);

-- Get the role IDs
SET @l1_role_id = (SELECT id FROM approvalRoles WHERE code = 'L1_APPROVER' LIMIT 1);
SET @l2_role_id = (SELECT id FROM approvalRoles WHERE code = 'L2_APPROVER' LIMIT 1);

-- Link L1 stage to L1 Approver role
INSERT INTO stageApprovers (stageId, approverType, approverReference, priority, isBackup)
VALUES (@l1_stage_id, 'approval_role', @l1_role_id, 1, false);

-- Link L2 stage to L2 Approver role
INSERT INTO stageApprovers (stageId, approverType, approverReference, priority, isBackup)
VALUES (@l2_stage_id, 'approval_role', @l2_role_id, 1, false);

-- Assign admin user to both approval roles
INSERT INTO userApprovalRoles (userId, approvalRoleId, isPrimary, isActive)
SELECT 1, @l1_role_id, true, true
WHERE NOT EXISTS (SELECT 1 FROM userApprovalRoles WHERE userId = 1 AND approvalRoleId = @l1_role_id);

INSERT INTO userApprovalRoles (userId, approvalRoleId, isPrimary, isActive)
SELECT 1, @l2_role_id, true, true
WHERE NOT EXISTS (SELECT 1 FROM userApprovalRoles WHERE userId = 1 AND approvalRoleId = @l2_role_id);

